let wikiRequestIndex = 0;

export function resetWikiFixtureState() {
  wikiRequestIndex = 0;
}

export function nextWikipediaResponse(requestUrl: URL) {
  const languageId = requestUrl.searchParams.get('variant') ?? 'en';
  const batch = wikiArticleBatches[wikiRequestIndex % wikiArticleBatches.length];

  wikiRequestIndex += 1;

  return {
    batchcomplete: true,
    query: {
      pages: Object.fromEntries(
        batch.map((article) => [
          article.pageid,
          {
            canonicalurl: article.url,
            extract: article.extract,
            pageid: article.pageid,
            thumbnail: article.thumbnail,
            title: article.title,
            varianttitles: {
              [languageId]: article.displaytitle,
            },
          },
        ]),
      ),
    },
  };
}

